class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.weights1 = [];
        this.weights2 = [];
        this.biases1 = [];
        this.bias2 = 0.5;
        this.lastNeuronCount = 0;
        this.initWeights(initialInputs.neuronCount);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    initWeights(count) {
        this.weights1 = [];
        this.weights2 = [];
        this.biases1 = [];
        for (let i = 0; i < count; i++) {
            this.weights1.push([Math.sin(i * 1.5) * 2, Math.cos(i * 2.1) * 2]);
            this.biases1.push(Math.sin(i * 0.7));
            this.weights2.push(Math.cos(i * 1.1) * 2);
        }
        this.lastNeuronCount = count;
    }

    resize() {
        this.width = this.container.clientWidth;
        this.height = this.container.clientHeight;
        this.canvas.width = this.width * window.devicePixelRatio;
        this.canvas.height = this.height * window.devicePixelRatio;
        this.canvas.style.width = this.width + 'px';
        this.canvas.style.height = this.height + 'px';
        this.ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    }

    activate(x, type) {
        if (type === 'relu') return Math.max(0, x);
        if (type === 'sigmoid') return 1 / (1 + Math.exp(-x));
        if (type === 'tanh') return Math.tanh(x);
        return x;
    }

    forward(ins, inputs) {
        let hidden = [];
        for (let i = 0; i < inputs.neuronCount; i++) {
            let sum = ins[0] * this.weights1[i][0] * inputs.weightScale + ins[1] * this.weights1[i][1] * inputs.weightScale + this.biases1[i];
            hidden.push(this.activate(sum, inputs.activation));
        }
        let outSum = 0;
        for (let i = 0; i < inputs.neuronCount; i++) {
            outSum += hidden[i] * this.weights2[i] * inputs.weightScale;
        }
        return this.activate(outSum + this.bias2, 'sigmoid');
    }

    update(inputs) {
        if (inputs.neuronCount !== this.lastNeuronCount) {
            this.initWeights(inputs.neuronCount);
        }

        const ctx = this.ctx;
        ctx.clearRect(0, 0, this.width, this.height);

        const halfW = this.width / 2;

        if (inputs.showGrid) {
            const gridSize = 40;
            const stepX = (this.width / 2) / gridSize;
            const stepY = this.height / gridSize;
            for (let i = 0; i < gridSize; i++) {
                for (let j = 0; j < gridSize; j++) {
                    const nx = (i / gridSize) * 2 - 1;
                    const ny = (j / gridSize) * 2 - 1;
                    const val = this.forward([nx, ny], inputs);
                    ctx.fillStyle = `rgba(59, 130, 246, ${val})`;
                    ctx.fillRect(halfW + i * stepX, j * stepY, stepX + 1, stepY + 1);
                    ctx.fillStyle = `rgba(239, 68, 68, ${1 - val})`;
                    ctx.fillRect(halfW + i * stepX, j * stepY, stepX + 1, stepY + 1);
                }
            }
        }

        const layers = [2, inputs.neuronCount, 1];
        const layerX = [halfW * 0.15, halfW * 0.5, halfW * 0.85];
        const nodeRadius = 12;

        layers.forEach((count, lIdx) => {
            const x = layerX[lIdx];
            const spacing = (this.height - 100) / (count + 1);
            for (let i = 0; i < count; i++) {
                const y = 50 + (i + 1) * spacing;

                if (lIdx < layers.length - 1) {
                    const nextCount = layers[lIdx + 1];
                    const nextSpacing = (this.height - 100) / (nextCount + 1);
                    for (let j = 0; j < nextCount; j++) {
                        const nextY = 50 + (j + 1) * nextSpacing;
                        let w = 0;
                        if (lIdx === 0) w = this.weights1[j][i];
                        else w = this.weights2[i];

                        ctx.beginPath();
                        ctx.moveTo(x, y);
                        ctx.lineTo(layerX[lIdx + 1], nextY);
                        ctx.lineWidth = Math.abs(w) * inputs.weightScale * 1.5;
                        ctx.strokeStyle = w > 0 ? '#3b82f6' : '#ef4444';
                        ctx.globalAlpha = 0.4;
                        ctx.stroke();
                        ctx.globalAlpha = 1.0;
                    }
                }

                ctx.beginPath();
                ctx.arc(x, y, nodeRadius, 0, Math.PI * 2);
                ctx.fillStyle = '#ffffff';
                ctx.fill();
                ctx.strokeStyle = '#1e293b';
                ctx.lineWidth = 2;
                ctx.stroke();
            }
        });

        ctx.fillStyle = '#1e293b';
        ctx.font = 'bold 14px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText('INPUT LAYER', layerX[0], 30);
        ctx.fillText('HIDDEN LAYER', layerX[1], 30);
        ctx.fillText('OUTPUT', layerX[2], 30);
        ctx.fillText('DECISION LANDSCAPE', halfW + halfW/2, 30);
    }
}
